// PHASE 8: Emergency & Critical Care Nursing (100 Questions)
const phase8 = {
  phase: 8, title: "Emergency & Critical Care", icon: "🚨", color: "#c0392b",
  questions: [
    { id:"p8q1", question:"The PRIMARY survey in trauma assessment follows which mnemonic?", options:["SAMPLE","ABCDE (Airway, Breathing, Circulation, Disability, Exposure)","OPQRST","SBAR"], answer:1, explanation:"Primary survey: A-Airway (with C-spine control), B-Breathing/ventilation, C-Circulation/hemorrhage control, D-Disability (neuro status, GCS), E-Exposure/Environment (undress patient, prevent hypothermia). Life threats identified and treated immediately." },
    { id:"p8q2", question:"During CPR, the compression-to-ventilation ratio for adults is:", options:["15:2","30:2 (single or two-rescuer adult CPR)","5:1","20:2"], answer:1, explanation:"AHA guidelines: 30:2 (30 compressions, 2 breaths) for adults with an unprotected airway. With advanced airway (ETT, LMA): continuous compressions at 100–120/min, 1 breath every 6 seconds." },
    { id:"p8q3", question:"What is the FIRST drug administered in cardiac arrest (ventricular fibrillation)?", options:["Atropine","Amiodarone","Epinephrine 1 mg IV/IO every 3–5 min","Lidocaine"], answer:2, explanation:"In VF/pVT: defibrillate first, then CPR, then epinephrine 1 mg IV/IO after 2nd shock (ACLS 2020 update recommends epinephrine early). Amiodarone 300 mg IV for shock-refractory VF/pVT." },
    { id:"p8q4", question:"Tension pneumothorax requires immediate:", options:["Chest X-ray","CT scan","Needle decompression (2nd ICS, MCL) — do NOT wait for imaging","IV antibiotics"], answer:2, explanation:"Tension pneumothorax: life-threatening emergency. Air accumulates under pressure, compressing mediastinum. Immediate needle decompression: 2nd intercostal space, midclavicular line (or 4th/5th ICS, AAL). Then chest tube insertion." },
    { id:"p8q5", question:"Classic signs of tension pneumothorax include:", options:["Fever and productive cough","Tracheal deviation AWAY from affected side, absent breath sounds, JVD, hypotension, tachycardia","Bilateral wheeze","Productive cough and hemoptysis"], answer:1, explanation:"Tension pneumothorax: trachea deviates away from affected side (late sign), absent breath sounds on affected side, JVD (obstructed venous return), hypotension, tachycardia. Tension = obstructive shock." },
    { id:"p8q6", question:"The universal antidote for a cardiac arrest from any shockable rhythm is:", options:["Atropine","CPR + Defibrillation + Epinephrine","Amiodarone alone","Lidocaine alone"], answer:1, explanation:"For VF/pVT (shockable rhythms): high-quality CPR (minimize interruptions), early defibrillation, epinephrine 1 mg every 3–5 min, amiodarone (300 mg then 150 mg) if shock-refractory, treat reversible causes (H's and T's)." },
    { id:"p8q7", question:"The '4 H's and 4 T's' in ACLS represent reversible causes of cardiac arrest. Which is a '4 H'?", options:["Tamponade","Hypovolemia","Thrombosis","Tension pneumothorax"], answer:1, explanation:"4 H's: Hypovolemia, Hypoxia, Hydrogen ion (acidosis), Hypo/Hyperkalemia (and Hypothermia). 4 T's: Tension pneumothorax, Tamponade (cardiac), Toxins, Thrombosis (pulmonary/coronary). Treat all in PEA/asystole." },
    { id:"p8q8", question:"Cardiac tamponade presents with Beck's triad:", options:["Hypertension, tachycardia, fever","Hypotension, muffled heart sounds, JVD (distended neck veins)","Chest pain, cough, hemoptysis","Tachycardia, hypertension, peripheral edema"], answer:1, explanation:"Beck's triad: Hypotension + Muffled heart sounds + JVD (elevated JVP). Pulsus paradoxus (BP drops >10 mmHg on inspiration). Treatment: pericardiocentesis (needle aspiration) emergently." },
    { id:"p8q9", question:"Normal SpO2 range for a healthy adult is:", options:["88–92%","92–95%","95–100%","90–94%"], answer:2, explanation:"Normal SpO2: 95–100%. <94%: supplemental O2 needed. <90%: severe hypoxemia, emergency O2. COPD target: 88–92%. SpO2 can be falsely normal in CO poisoning (COHb measured as oxyhemoglobin by pulse oximetry)." },
    { id:"p8q10", question:"The START triage system categorizes victims as:", options:["Critical, Serious, Minor","Immediate (Red), Delayed (Yellow), Minimal (Green), Expectant (Black)","Priority 1–5","A, B, C, D"], answer:1, explanation:"START (Simple Triage and Rapid Treatment): Immediate/Red (<30 sec RR, cap refill >2 sec, or no GCS follow commands), Delayed/Yellow (stable, can wait), Minor/Green (walking wounded), Expectant/Black (dead or unsurvivable)." },
    { id:"p8q11", question:"A patient with crush injury to the lower limbs develops dark tea-colored urine. This indicates:", options:["Urinary tract infection","Rhabdomyolysis with myoglobinuria — risk of acute kidney injury","Normal finding post-trauma","Hematuria from kidney trauma"], answer:1, explanation:"Rhabdomyolysis: muscle breakdown releases myoglobin → tea/cola-colored urine → acute tubular necrosis and kidney injury. Treatment: aggressive IV hydration (250 mL/hr NS), target UO 200–300 mL/hr, consider alkalization." },
    { id:"p8q12", question:"Glasgow Coma Scale (GCS) assesses:", options:["Only pupil size","Eye opening (E, 1–4), Verbal response (V, 1–5), Motor response (M, 1–6) — total 3–15","Only motor function","Respiratory status only"], answer:1, explanation:"GCS: E+V+M = 3 (min) to 15 (max). Score ≤8 = severe TBI, intubation indicated. Score 9–12 = moderate. Score 13–15 = mild. Best motor response is most predictive of outcome." },
    { id:"p8q13", question:"Which is the MOST sensitive early indicator of shock?", options:["Hypotension (systolic <90 mmHg)","Tachycardia and narrowing pulse pressure","Oliguria","Altered mental status"], answer:1, explanation:"Tachycardia is the earliest sign of shock. Hypotension is a LATE sign (blood pressure maintained by compensatory vasoconstriction until ~30% blood volume is lost). Narrowing pulse pressure precedes hypotension." },
    { id:"p8q14", question:"A patient arrives with suspected poisoning. After securing airway/breathing, the NEXT step is:", options:["Induce vomiting immediately","Administer activated charcoal (within 1 hour of ingestion for most toxins, if no contraindication)","Call poison control and assess for specific antidotes","Give milk to neutralize the toxin"], answer:2, explanation:"Poisoning management: ABC first, identify toxin (call poison control), activated charcoal (within 1 hour, if alert, no caustic/hydrocarbon ingestion, no bowel obstruction), specific antidotes if available, supportive care." },
    { id:"p8q15", question:"Which assessment tool is used to detect early sepsis?", options:["GCS alone","qSOFA (quick Sequential Organ Failure Assessment): RR≥22, AMS, SBP≤100 — 2+ criteria = high risk for sepsis","APGAR score","AVPU scale"], answer:1, explanation:"qSOFA (2016 Sepsis-3 definition): Respiratory rate ≥22/min, Altered mentation, SBP ≤100 mmHg. ≥2 criteria: high risk of organ dysfunction/death — initiate sepsis workup. SOFA score used in ICU for organ dysfunction." },
    { id:"p8q16", question:"Surviving Sepsis Campaign 'Hour-1 Bundle' includes:", options:["Blood culture AFTER antibiotics","Measure lactate, blood cultures (×2 before antibiotics), broad-spectrum antibiotics, 30 mL/kg crystalloid for hypotension/lactate≥4, vasopressors if hypotension persists","IV steroids first","Diuretics for fluid management"], answer:1, explanation:"Sepsis Hour-1 Bundle: 1) Measure lactate (>4 mmol/L = severe), 2) Blood cultures ×2 before antibiotics, 3) Broad-spectrum IV antibiotics within 1 hour, 4) 30 mL/kg IV crystalloid for hypotension or lactate≥4, 5) Vasopressors to maintain MAP≥65." },
    { id:"p8q17", question:"A patient on a ventilator has sudden drop in SpO2 and increased peak airway pressure. The DOPE mnemonic helps check:", options:["Drug overdose possibilities","Displacement of ETT, Obstruction (secretions/kink), Pneumothorax, Equipment failure","Depth of sedation","Documentation of events"], answer:1, explanation:"DOPE: Displacement (ETT out of position — check position), Obstruction (mucus plug — suction), Pneumothorax (decompressed if suspected), Equipment failure (bag-mask ventilate if in doubt). First action: disconnect from ventilator and bag-mask." },
    { id:"p8q18", question:"Cushing's reflex (triad) indicates:", options:["Early septic shock","Critically raised intracranial pressure with impending brainstem herniation: hypertension + bradycardia + irregular respirations","Anaphylaxis","Cardiogenic shock"], answer:1, explanation:"Cushing's reflex (triad): rising ICP compresses brainstem → hypertension (wide pulse pressure), reflex bradycardia, and irregular breathing (Cheyne-Stokes or agonal breathing). Very late sign of herniation — brain death may be imminent." },
    { id:"p8q19", question:"Which acid-base disorder results from hypoventilation (CO2 retention)?", options:["Metabolic acidosis","Metabolic alkalosis","Respiratory acidosis (CO2 + H2O → H2CO3 → H+ + HCO3-, pH falls)","Respiratory alkalosis"], answer:2, explanation:"Respiratory acidosis: hypoventilation → CO2 retention → increased H2CO3 → decreased pH. Causes: COPD, sedative overdose, chest wall trauma, neuromuscular disease. ABG: pH <7.35, PaCO2 >45 mmHg." },
    { id:"p8q20", question:"The AVPU scale assesses:", options:["Pain severity","Level of consciousness: Alert, responds to Voice, responds to Pain, Unresponsive","Vital signs","Respiratory function"], answer:1, explanation:"AVPU: rapid consciousness assessment. Alert (orientated), Voice (responds to verbal stimulus), Pain (responds to painful stimulus — trapezius squeeze, sternal rub), Unresponsive (no response to any stimulus). Unresponsive ≈ GCS ≤8." },
    { id:"p8q21", question:"Triage priority in mass casualty incident: a patient with absent radial pulse and RR 32/min is classified as:", options:["Green (minor)","Yellow (delayed)","Red (immediate)","Black (expectant)"], answer:2, explanation:"START triage: RR >30/min OR absent radial pulse (cap refill >2 sec) OR cannot follow commands = Red (Immediate). This patient meets two Red criteria. Requires immediate intervention to survive." },
    { id:"p8q22", question:"A patient in anaphylaxis — epinephrine is given:", options:["IV push first","IM into lateral thigh (vastus lateralis) — 0.3–0.5 mg of 1:1000 concentration","SC only","Nebulized only"], answer:1, explanation:"Epinephrine 1:1000 (0.3–0.5 mg) IM into lateral thigh is first-line for anaphylaxis. IM has faster absorption than SC. Lateral thigh preferred over deltoid (better perfusion). Repeat every 5–15 min if needed. IV epinephrine only in cardiac arrest." },
    { id:"p8q23", question:"A patient with suspected cervical spine injury needs intubation. The SAFEST method is:", options:["Blind nasotracheal intubation","Rapid sequence intubation (RSI) with manual in-line stabilization (MILS)","Hyperflex the neck for better view","Cricothyrotomy first"], answer:1, explanation:"C-spine injury + airway need: RSI with manual in-line stabilization (maintain neutral alignment, do NOT apply traction). Video laryngoscopy preferred. Surgical airway if cannot intubate." },
    { id:"p8q24", question:"Normal central venous pressure (CVP) and what does elevated CVP suggest?", options:["0–2 mmHg; elevated = dehydration","8–12 cmH2O; elevated CVP = fluid overload, right heart failure, or cardiac tamponade","15–20 mmHg; normal finding","Negative values; elevated = hypovolemia"], answer:1, explanation:"Normal CVP: 2–8 mmHg (or 8–12 cmH2O). High CVP: fluid overload, right heart failure, cardiac tamponade, pulmonary hypertension, tension pneumothorax. Low CVP: hypovolemia." },
    { id:"p8q25", question:"Which type of shock has WARM, FLUSHED skin (as opposed to cold, clammy)?", options:["Hypovolemic shock","Cardiogenic shock","Neurogenic shock (distributive — loss of sympathetic tone)","Obstructive shock"], answer:2, explanation:"Distributive shock (neurogenic, septic early, anaphylactic): vasodilation → warm flushed skin, bounding pulse, wide pulse pressure. Neurogenic: bradycardia (loss of sympathetic) + hypotension. Others have cold, clammy skin from vasoconstriction." },
    { id:"p8q26", question:"The Parkland formula for burns fluid resuscitation: a 70 kg patient with 40% TBSA burn requires:", options:["7,000 mL in 24 hours (half in first 8 hours from burn)","11,200 mL (4 mL × 70 × 40) LR in 24 hours — half in first 8 hours from time of injury, half in next 16 hours","5,600 mL in 12 hours","4,000 mL total"], answer:1, explanation:"Parkland formula: 4 mL × kg × % TBSA = 4 × 70 × 40 = 11,200 mL LR. Half (5,600 mL) in first 8 hours from TIME OF BURN, half in next 16 hours. Monitor UO (0.5–1 mL/kg/hr). Add 2 mL × kg × % TBSA for children." },
    { id:"p8q27", question:"In a trauma patient, unresponsive with massive neck swelling after a stab wound. The PRIORITY is:", options:["CT scan of neck","Chest X-ray","Secure airway IMMEDIATELY — surgical airway may be needed","IV access and fluid resuscitation"], answer:2, explanation:"Expanding neck hematoma after trauma: immediate airway threat due to tracheal compression/distortion. Attempt intubation early (before swelling worsens). If unable: surgical airway (cricothyrotomy). Airway is always priority 1." },
    { id:"p8q28", question:"A patient in ICU develops sudden tachycardia, hypotension, decreased SpO2, and unilateral absent breath sounds 2 days post-thoracotomy. The PRIORITY action:", options:["Order chest X-ray","Increase FiO2","Immediately decompress with needle (suspected tension pneumothorax) — clinical diagnosis, do NOT wait for X-ray","Increase IV fluids"], answer:2, explanation:"Clinical diagnosis of tension pneumothorax: immediate needle decompression (2nd ICS, MCL). Waiting for X-ray is dangerous — patient can arrest. After needle decompression, insert chest tube." },
    { id:"p8q29", question:"Normal arterial blood gas (ABG) values:", options:["pH 7.25, PaCO2 50, HCO3 22","pH 7.35–7.45, PaCO2 35–45 mmHg, HCO3 22–26 mEq/L, PaO2 80–100 mmHg","pH 7.50, PaCO2 30, HCO3 28","pH 7.30, PaCO2 40, HCO3 18"], answer:1, explanation:"Normal ABG: pH 7.35–7.45, PaCO2 35–45 mmHg (respiratory), HCO3 22–26 mEq/L (metabolic), PaO2 80–100 mmHg, SaO2 >95%. Use ROME: Respiratory Opposite, Metabolic Equal to identify primary disorder." },
    { id:"p8q30", question:"A patient with acute ST-elevation MI (STEMI) — time target for primary PCI is:", options:["Within 2 hours","Within 90 minutes of first medical contact (door-to-balloon time)","Within 4 hours","Within 6 hours"], answer:1, explanation:"STEMI: primary PCI (percutaneous coronary intervention) within 90 minutes of first medical contact (door-to-balloon). If PCI unavailable, fibrinolysis within 30 minutes of arrival (door-to-needle). Every minute saves myocardium." },
    { id:"p8q31", question:"Neurogenic shock occurs due to:", options:["Massive blood loss","Loss of sympathetic tone after spinal cord injury (T6 or above) — vasodilation, hypotension, bradycardia","Overwhelming infection","Anaphylaxis"], answer:1, explanation:"Neurogenic shock: SCI at T6 or above disrupts sympathetic outflow → vasodilation (warm, flushed) + bradycardia (unopposed parasympathetic). Treatment: IV fluids, vasopressors (norepinephrine), atropine for bradycardia." },
    { id:"p8q32", question:"What does PEEP (positive end-expiratory pressure) do in mechanically ventilated patients?", options:["Increases tidal volume only","Prevents alveolar collapse at end of expiration, improves oxygenation, reduces atelectasis","Reduces oxygen delivery","Decreases lung compliance"], answer:1, explanation:"PEEP: maintains positive pressure at end of expiration, keeping alveoli open (prevents collapse). Improves oxygenation (FRC increases, V/Q mismatch decreases). Used in ARDS. High PEEP can reduce cardiac output (impedes venous return)." },
    { id:"p8q33", question:"A patient with suspected CO (carbon monoxide) poisoning. SpO2 reads 99%. The nurse should:", options:["Reassure the patient — SpO2 is normal","Recognize SpO2 is falsely normal in CO poisoning — administer 100% O2 via NRM, check COHb level","Give supplemental O2 at 2 L/min","Discharge the patient"], answer:1, explanation:"CO binds hemoglobin (250× stronger than O2), forming COHb. Pulse oximetry CANNOT distinguish COHb from OxyHb — reads falsely high. Symptoms: headache, confusion, cherry-red lips. Tx: 100% O2 (reduces COHb half-life from 5h to 90 min)." },
    { id:"p8q34", question:"Which arrhythmia is treated with SYNCHRONIZED cardioversion (not defibrillation)?", options:["Ventricular fibrillation","Pulseless ventricular tachycardia","Unstable atrial fibrillation, SVT, atrial flutter — hemodynamically UNSTABLE with a pulse","Asystole"], answer:2, explanation:"Synchronized cardioversion: for hemodynamically UNSTABLE patients with a pulse (AF, SVT, flutter, stable VT). Synchronized to avoid delivering shock on T-wave (→ VF). Defibrillation (unsynchronized) for pulseless VF/pVT." },
    { id:"p8q35", question:"A patient develops severe hypotension after starting an IV antibiotic. The nurse suspects anaphylaxis. FIRST action:", options:["Stop the infusion, call for help","Stop infusion and immediately administer IM epinephrine 0.3–0.5 mg into lateral thigh + call for help","Administer IV diphenhydramine first","Increase IV fluid rate only"], answer:1, explanation:"Anaphylaxis: stop causative agent, IM epinephrine lateral thigh (0.3–0.5 mg of 1:1000) is the FIRST treatment. Then: lay flat + elevate legs (if hypotensive), O2, IV access, IV fluids, antihistamines, corticosteroids (secondary)." },
    { id:"p8q36", question:"The ventilator setting 'FiO2' refers to:", options:["Frequency of inspiration","Fraction of inspired oxygen (0.21 = room air, 1.0 = 100% oxygen)","Force of inspiration","Flow rate of IV medications"], answer:1, explanation:"FiO2: fraction of inspired oxygen (21% in room air). Range on ventilator: 0.21–1.0. Start at 1.0 in emergencies, titrate down to lowest FiO2 maintaining SpO2 ≥95% (to avoid oxygen toxicity). Target SpO2 94–98% in most ventilated patients." },
    { id:"p8q37", question:"A patient is found unresponsive. After calling for help, the next step (ACLS/BLS) is:", options:["Give 2 rescue breaths first","Check for pulse (10 seconds maximum) and begin CPR if absent or abnormal","Place in recovery position","Call family first"], answer:1, explanation:"BLS sequence: Confirm unresponsiveness → Call for help/AED → Check carotid pulse (≤10 seconds) → If no pulse: start CPR (30:2). If AED arrives: attach and follow prompts. Push hard (5–6 cm), fast (100–120/min), minimize interruptions." },
    { id:"p8q38", question:"A patient with acute pulmonary edema (severe left heart failure). The PRIORITY position:", options:["Supine flat","Left lateral Sims position","High Fowler's (sitting upright, legs dependent) to reduce preload and ease breathing","Trendelenburg"], answer:2, explanation:"Acute pulmonary edema: sit patient upright (High Fowler's), legs dangling if possible (reduces preload). Administer high-flow O2, IV furosemide, GTN (nitroglycerin), morphine (reduces preload/anxiety). CPAP/NIPPV may be needed." },
    { id:"p8q39", question:"Hypertensive emergency (hypertensive crisis with organ damage) — blood pressure should be reduced by what amount in the first hour?", options:["Normalize blood pressure completely within 1 hour","Reduce MAP by no more than 20–25% in the first hour — then gradually to 160/100 over 2–6 hours","Reduce to <120/80 mmHg within 30 minutes","No reduction needed in the first hour"], answer:1, explanation:"Hypertensive emergency: reduce MAP by ≤25% in first hour (too rapid reduction → ischemic stroke, MI, acute kidney injury). Then 160/100 over 2–6 hours. Exceptions: aortic dissection (immediate reduction to SBP <120)." },
    { id:"p8q40", question:"A patient with suspected aortic dissection. Which drug class is CONTRAINDICATED?", options:["Beta-blockers","ACE inhibitors","Vasodilators without beta-blockade first (can increase aortic wall stress via reflex tachycardia)","Opioids for pain"], answer:2, explanation:"Aortic dissection: control BP AND heart rate. Beta-blockers FIRST (esmolol IV) to reduce aortic wall stress (rate + pressure), THEN vasodilators (sodium nitroprusside). Vasodilators alone cause reflex tachycardia → worse dissection." },
    { id:"p8q41", question:"Urine output indicating adequate resuscitation in a critically ill adult:", options:["0.3 mL/kg/hr","0.5–1 mL/kg/hr (at least 30 mL/hr in adults)","2 mL/kg/hr","1 mL/hour regardless of weight"], answer:1, explanation:"Adequate resuscitation marker: UO ≥0.5 mL/kg/hr (adults). In burns: target 0.5–1 mL/kg/hr. Oliguria (<0.5 mL/kg/hr) indicates inadequate perfusion. Polyuria may indicate DI, glucose-induced osmotic diuresis, or recovery phase." },
    { id:"p8q42", question:"A patient in status asthmaticus does NOT respond to bronchodilators and shows signs of respiratory fatigue. The nurse prepares for:", options:["Chest X-ray","Increase steroid dose only","Non-invasive positive pressure ventilation (NIPPV/BiPAP) or intubation with mechanical ventilation","Discharge with inhaler prescription"], answer:2, explanation:"Near-fatal asthma: silent chest, rising PaCO2 (respiratory fatigue), altered consciousness, SpO2 <90% despite O2/bronchodilators → immediate escalation: NIPPV trial, prepare RSI for intubation. High PEEP + permissive hypercapnia strategy." },
    { id:"p8q43", question:"The CURB-65 score is used for:", options:["Trauma severity","Pneumonia severity and need for hospitalization: Confusion, Urea >7 mmol/L, RR≥30, BP<90/60, Age≥65","Cardiac arrest prognosis","Sepsis severity"], answer:1, explanation:"CURB-65: each criterion = 1 point. Score 0–1: outpatient treatment. Score 2: hospitalization. Score ≥3 (especially 4–5): ICU consideration. Mortality: score 0 = 0.7%, score 5 = 57%." },
    { id:"p8q44", question:"The nurse is caring for a patient with diabetic ketoacidosis (DKA). Which electrolyte requires CAREFUL monitoring during insulin therapy?", options:["Sodium","Calcium","Potassium — insulin shifts K+ into cells, causing hypokalemia","Magnesium primarily"], answer:2, explanation:"DKA: serum K+ may appear normal/elevated initially (acidosis shifts K+ out of cells) but total body K+ is depleted. Insulin therapy → K+ shifts intracellularly → hypokalemia → cardiac arrhythmias. Replace K+ if <3.5 mEq/L before insulin." },
    { id:"p8q45", question:"A patient with acute stroke — time window for IV tPA (alteplase) thrombolysis is:", options:["Within 1 hour","Within 3–4.5 hours of symptom onset (NIHSS scored, no contraindications)","Within 6 hours only","Within 12 hours"], answer:1, explanation:"IV alteplase (tPA): within 3–4.5 hours of ischemic stroke symptom onset. Door-to-needle target: 60 minutes. Contraindications: hemorrhagic stroke, BP >185/110, INR>1.7, platelet <100K, major surgery <14 days, prior ICH." },
    { id:"p8q46", question:"Which vasoactive drug is the FIRST-LINE vasopressor in septic shock?", options:["Epinephrine","Dopamine","Norepinephrine (noradrenaline) — alpha-1 agonist + some beta-1","Vasopressin alone"], answer:2, explanation:"Surviving Sepsis Campaign: norepinephrine is first-line vasopressor for septic shock (target MAP ≥65 mmHg). Vasopressin (0.03–0.04 U/min) can be added. Epinephrine: second-line. Dopamine: increased arrhythmia risk." },
    { id:"p8q47", question:"Which is the MOST common cause of preventable death in trauma patients?", options:["Head injuries","Spinal cord injuries","Uncontrolled hemorrhage (exsanguination)","Airway obstruction"], answer:2, explanation:"Uncontrolled hemorrhage is the most common cause of preventable traumatic death. Damage control resuscitation: permissive hypotension (SBP 80–90), minimize crystalloids, balanced blood product ratio (1:1:1 FFP:platelets:RBCs), TXA within 3 hours." },
    { id:"p8q48", question:"Abdominal aortic aneurysm (AAA) rupture presents with:", options:["Painless pulsatile abdominal mass only","Sudden severe tearing abdominal/back pain, hypotension, pulsatile abdominal mass — vascular emergency","Gradual onset epigastric pain","Fever and chills"], answer:1, explanation:"Ruptured AAA: classic triad — sudden severe tearing/ripping abdominal/back pain + hypotension + pulsatile abdominal mass. Majority die before reaching hospital. Immediate surgical intervention needed. Do NOT delay for CT if unstable." },
    { id:"p8q49", question:"A patient is intubated and on a ventilator. Ventilator alarm 'HIGH PRESSURE' sounds. The FIRST action:", options:["Increase sedation","Check for: kinked tubing, patient biting tube (bite block), secretions (suction), coughing, pneumothorax, bronchospasm","Increase FiO2","Change the ventilator mode"], answer:1, explanation:"High peak airway pressure alarm: check cause systematically — patient biting tube, kinked circuit, mucus plug (suction), bronchospasm (nebulize bronchodilator), pneumothorax (auscultate), fighting ventilator (reassess sedation/analgesia)." },
    { id:"p8q50", question:"The SOFA score in the ICU measures:", options:["Sedation level","Sequential Organ Failure Assessment — evaluates 6 organ systems (respiratory, coagulation, liver, cardiovascular, CNS, renal) to quantify organ dysfunction/failure","Pain severity","Nutrition status"], answer:1, explanation:"SOFA score (Sepsis-3): Respiratory (PaO2/FiO2), Coagulation (platelets), Liver (bilirubin), Cardiovascular (MAP/vasopressors), CNS (GCS), Renal (creatinine/UO). Total 0–24. Score ≥2 above baseline = organ dysfunction." },
    { id:"p8q51", question:"For which cardiac rhythm is atropine indicated?", options:["Ventricular fibrillation","Pulseless ventricular tachycardia","Symptomatic sinus bradycardia and AV block (first-line for symptomatic bradycardia)","Atrial fibrillation with rapid ventricular response"], answer:2, explanation:"Atropine 0.5 mg IV (repeat up to 3 mg): first-line for symptomatic bradycardia (hypotension, altered consciousness, chest pain). Not effective for complete heart block or Mobitz II. If atropine fails: transcutaneous pacing, then dopamine/epinephrine infusion." },
    { id:"p8q52", question:"Post-cardiac arrest care includes:", options:["Immediate discharge if stable","Targeted temperature management (TTM) at 32–36°C for 24–48 hours, monitoring for rearrest, neuroprognostication","Only monitoring","Immediate aggressive rehabilitation"], answer:1, explanation:"Post-ROSC care: TTM (32–36°C for 24h — reduces neurological injury), hemodynamic optimization (MAP ≥65, SpO2 94–98%, normocarbia), treat underlying cause (cath lab for STEMI), avoid hyperthermia and hyperoxia." },
    { id:"p8q53", question:"A nurse performing ET tube suctioning should suction for no longer than:", options:["30 seconds","20 seconds","10–15 seconds (pre-oxygenate 100% O2 before each pass)","5 seconds"], answer:2, explanation:"ETT suctioning: pre-oxygenate with 100% O2, insert catheter to carina (not beyond), apply suction while withdrawing with rotating motion for ≤10–15 seconds. Monitor HR, SpO2. Limit to 2–3 passes. Catheter size: ETT diameter (mm) × 2 = maximum catheter size (Fr)." },
    { id:"p8q54", question:"Which assessment indicates that a chest tube is functioning properly?", options:["Constant bubbling in water-seal chamber","Tidaling (fluid fluctuating) in water-seal chamber, minimal drainage","No drainage at all","Air leak in collection chamber always"], answer:1, explanation:"Properly functioning chest tube: tidaling (water oscillates with breathing — confirms patency), drainage decreasing (resolving hemothorax/effusion). Continuous bubbling = air leak (may be at insertion site, connections, or from lung). No tidaling = blocked tube." },
    { id:"p8q55", question:"The ABCDE approach in sepsis/resuscitation stands for:", options:["Assess, Balance, Calculate, Diagnose, Evaluate","Airway, Breathing, Circulation, Disability, Exposure — systematic assessment and intervention","Administer, Bolus, Check, Diagnose, Escalate","Antibiotics, Blood culture, Culture, Drain, Escalate"], answer:1, explanation:"ABCDE approach is universal across all emergency and critical care presentations: Airway (open/protected?), Breathing (adequate? SpO2?), Circulation (BP, HR, perfusion, IV access), Disability (GCS, pupils, glucose), Exposure (undress, assess fully, temperature)." },
    { id:"p8q56", question:"A patient with acute liver failure develops confusion and asterixis. Ammonia level is 180 μmol/L. Treatment includes:", options:["High protein diet","Lactulose (to reduce ammonia absorption) + rifaximin, protein restriction — treat precipitants","Increased IV fluids","Antibiotics for hepatitis"], answer:1, explanation:"Hepatic encephalopathy: elevated ammonia from gut bacteria. Treatment: lactulose (acidifies gut → traps NH4+, laxative effect → faster elimination), rifaximin (reduces gut urease-producing bacteria), limit but don't eliminate protein (BCAA preferred)." },
    { id:"p8q57", question:"Permissive hypotension in penetrating trauma management means:", options:["Lowering BP with medications","Targeting SBP 80–90 mmHg with limited fluid resuscitation — minimizes clot disruption until surgical hemorrhage control","Allowing BP to drop to any level","Withholding all fluids"], answer:1, explanation:"Permissive hypotension (damage control resuscitation): target SBP 80–90 mmHg (MAP 50 mmHg) until surgical hemorrhage control. Excess crystalloids dilute clotting factors and worsen coagulopathy. Use balanced blood products (1:1:1 FFP:PLT:PRBCs)." },
    { id:"p8q58", question:"Which is the gold standard for confirming correct endotracheal tube (ETT) placement?", options:["Chest rise only","Auscultation of bilateral breath sounds","Colorimetric CO2 detector or waveform capnography (EtCO2) + chest X-ray confirmation","Pulse oximetry improvement"], answer:2, explanation:"ETT placement confirmation: waveform capnography (gold standard — continuous EtCO2 waveform) confirms tracheal placement. Colorimetric CO2 detector: purple → yellow with CO2 = tracheal. Then CXR for tip position (2–3 cm above carina)." },
    { id:"p8q59", question:"Which intervention is indicated for a patient with symptomatic complete heart block (3rd degree AV block)?", options:["Atropine alone","IV amiodarone","Transcutaneous (external) pacing immediately while preparing for transvenous pacing","Adenosine"], answer:2, explanation:"Complete (3rd degree) AV block: no conduction between atria and ventricles. Symptomatic: ventricular rate too slow → transcutaneous pacing (bridge), then transvenous pacing, then permanent pacemaker. Atropine unreliable for complete block." },
    { id:"p8q60", question:"A patient on TPN (total parenteral nutrition) develops sudden onset confusion, hypoglycemia, and tachycardia when the infusion is stopped abruptly. This is:", options:["Normal response","Rebound hypoglycemia from abrupt TPN discontinuation — always taper TPN","Sepsis from TPN line","Electrolyte imbalance only"], answer:1, explanation:"TPN: should NEVER be stopped abruptly — pancreas continues producing insulin → rebound hypoglycemia. Always taper over 1–2 hours before stopping. If must stop urgently: infuse 10% dextrose at same rate temporarily." },
    { id:"p8q61", question:"Normal intracranial pressure (ICP) range:", options:["0–5 mmHg","7–15 mmHg (2–15 mmHg)","20–30 mmHg","30–40 mmHg"], answer:1, explanation:"Normal ICP: 7–15 mmHg (adults). Treatment threshold typically ≥20–22 mmHg. Cerebral Perfusion Pressure (CPP) = MAP − ICP. Target CPP ≥60 mmHg in TBI. ICP >20: head elevation, sedation, osmotherapy (mannitol/hypertonic saline), hyperventilation (temporary)." },
    { id:"p8q62", question:"A trauma patient receives 4 units of packed red blood cells. A nurse monitors for which transfusion complication?", options:["Hyperthermia","Transfusion-Related Acute Lung Injury (TRALI) — bilateral pulmonary infiltrates, hypoxia within 6 hours","Hypertension","Thrombosis"], answer:1, explanation:"TRALI: non-cardiogenic pulmonary edema within 6 hours of transfusion. Bilateral infiltrates, hypoxia (SpO2 <90%), fever, hypotension. Leading cause of transfusion-related mortality. Treatment: supportive (O2, mechanical ventilation). Stop transfusion." },
    { id:"p8q63", question:"The 'lethal triad' in trauma refers to:", options:["Hypotension, tachycardia, altered consciousness","Hypothermia + coagulopathy + metabolic acidosis — each worsens the others, causing death","Tension pneumo + tamponade + hemorrhage","Head injury + chest injury + abdominal injury"], answer:1, explanation:"Trauma lethal triad: Hypothermia (impairs clotting factors, platelet function) + Coagulopathy (impairs hemorrhage control) + Acidosis (impairs cardiac function, clotting). Damage control surgery aims to prevent/reverse this triad." },
    { id:"p8q64", question:"A patient with hyperosmolar hyperglycemic state (HHS) has glucose 900 mg/dL. FIRST priority is:", options:["Insulin bolus immediately","Aggressive IV fluid resuscitation (normal saline) — profound dehydration is the primary problem","Bicarbonate infusion","Potassium replacement first"], answer:1, explanation:"HHS (type 2 DM, elderly): extreme hyperglycemia + severe dehydration + hyperosmolarity. IV fluids are the FIRST priority (profound deficit of 8–10 L). Insulin is added slowly AFTER fluid resuscitation begins. No ketoacidosis (unlike DKA)." },
    { id:"p8q65", question:"A drowning victim is rescued and appears pale, cold, and in cardiac arrest. The principle 'not dead until warm and dead' means:", options:["Never resuscitate drowning victims","Continue CPR during active rewarming — profound hypothermia can protect the brain, ROSC possible even after prolonged cardiac arrest","Stop CPR if unresponsive after 10 minutes","Warm before giving medications"], answer:1, explanation:"Hypothermic cardiac arrest: continue CPR and active rewarming (ECMO/CPB ideally). Hypothermia reduces metabolic rate and protects the brain. Successful resuscitation reported after hours of CPR in severe hypothermia. 'Not dead until warm and dead.'" },
    { id:"p8q66", question:"Morphine is used cautiously in cardiogenic shock because:", options:["It causes tachycardia","It causes respiratory depression and may worsen hemodynamics — vasodilation + myocardial depression","It is contraindicated in all cardiac conditions","It does not provide pain relief"], answer:1, explanation:"Morphine in cardiogenic shock/STEMI: may cause respiratory depression, vasodilation (reduces preload — beneficial in pulmonary edema, but risky in hypotension), and antiemetic effects. Evidence of worse outcomes in STEMI with morphine (CRUSADE registry). Use cautiously." },
    { id:"p8q67", question:"A patient is admitted with rattlesnake bite. The nurse's PRIORITY intervention:", options:["Apply tourniquet above bite","Make incisions and suck venom","Immobilize extremity, keep below heart level, IV access, contact poison control, antivenom","Apply ice to the bite site"], answer:2, explanation:"Snakebite: immobilize extremity at or below heart level (reduces lymphatic spread), remove jewelry, large-bore IV, mark swelling borders, contact poison control/toxicologist, prepare antivenom (Crotalidae Fab — CroFab). Never: tourniquet, incision, suction, ice." },
    { id:"p8q68", question:"Which intervention is contraindicated in hemorrhagic stroke?", options:["Blood pressure control","Neurosurgical consultation","Anticoagulation or thrombolytics (tPA)","Airway management"], answer:2, explanation:"Hemorrhagic stroke: anticoagulants and thrombolytics are absolutely CONTRAINDICATED (worsen bleeding). Management: airway, BP control (controversial — some reduction to <140 systolic within 6 hours), neurosurgical consultation, reverse any anticoagulation." },
    { id:"p8q69", question:"During nasotracheal intubation, advancement of the tube should occur when:", options:["The patient exhales","The patient is apneic","During inspiration when the vocal cords open (listen for breath sounds through the tube)","During coughing"], answer:2, explanation:"Blind nasotracheal intubation (BNTB): pass tube through nostril, advance toward glottis. Advance during inspiration (cords open, air movement heard through tube = tube at glottis). Rapidly advance during next inspiration. Now largely replaced by video laryngoscopy." },
    { id:"p8q70", question:"A patient with suspected head injury has unequal pupils (anisocoria). This suggests:", options:["Normal variant","Uncal herniation compressing CN III on affected side — ipsilateral pupil dilated and fixed","Hyperglycemia","Opiate toxicity"], answer:1, explanation:"Fixed dilated pupil after head injury = uncal (transtentorial) herniation: the temporal lobe herniates through the tentorium, compressing CN III (oculomotor) and then the brainstem. Neurological emergency — immediate CT, neurosurgery." },
    { id:"p8q71", question:"A trauma patient has flat neck veins AND tracheal deviation AND absent breath sounds. This suggests:", options:["Cardiac tamponade (JVD present)","Simple pneumothorax","Tension pneumothorax with concurrent hypovolemia (masking JVD)","Hemothorax — flat veins from blood loss"], answer:3, explanation:"Hemothorax: blood in pleural space → absent breath sounds + flat neck veins (hypovolemia from blood loss). Tracheal deviation is more common in tension pneumothorax. In hemothorax: chest tube + fluid resuscitation + surgical control if massive." },
    { id:"p8q72", question:"Hyperkalemia treatment sequence (acute management):", options:["Kayexalate first","IV calcium gluconate (stabilize cardiac membranes) → insulin + dextrose (shift K+ into cells) → sodium bicarbonate → furosemide/kayexalate (eliminate K+) → dialysis if severe","Dialysis immediately","Furosemide only"], answer:1, explanation:"K+ treatment sequence: 1) Calcium gluconate IV (membrane stabilization, onset 1–3 min), 2) Insulin+D50 (shift K+ into cells, onset 15–30 min), 3) NaHCO3 if acidotic, 4) Furosemide/kayexalate/patiromer (eliminate K+), 5) Dialysis (definitive in renal failure)." },
    { id:"p8q73", question:"Massive transfusion protocol (MTP) is typically activated when a patient requires:", options:["1 unit of blood","≥10 units PRBCs in 24 hours (or ≥4 units in 1 hour) — with balanced ratio 1:1:1 PRBCs:FFP:platelets","Any blood transfusion","3 units of FFP"], answer:1, explanation:"MTP: ≥10 PRBCs/24h or ≥4 PRBCs/1h. Balanced resuscitation ratio of 1:1:1 (PRBCs:FFP:platelets) mimics whole blood, prevents dilutional coagulopathy. Also add: TXA (tranexamic acid) within 3 hours of injury, calcium." },
    { id:"p8q74", question:"Which position is used for a patient in hypovolemic shock WITHOUT head/spine injury?", options:["Trendelenburg (head down 10–15°) or modified Trendelenburg (elevate legs 15–30°, torso flat)","High Fowler's","Prone","Lateral"], answer:0, explanation:"Shock position: raise legs 15–30° (modified Trendelenburg/passive leg raise) to increase venous return. True Trendelenburg (head down) now controversial — may worsen respiratory mechanics. Elevate legs, keep torso flat, keep head flat." },
    { id:"p8q75", question:"A patient with acute decompensated heart failure on CPAP — what does CPAP provide?", options:["Only supplemental oxygen","Continuous positive airway pressure: improves oxygenation, reduces preload (reduces venous return), reduces work of breathing, recruits fluid from alveoli","Mechanical ventilation","Diuresis"], answer:1, explanation:"CPAP/NIPPV in acute pulmonary edema: improves oxygenation (splints alveoli open), reduces preload and afterload (reduced work of breathing), decreases need for intubation. Target: SpO2 >92%, respiratory rate <25." },
    { id:"p8q76", question:"A patient has received opioids post-operatively and has RR of 8/min with pinpoint pupils. Treatment:", options:["Increase oxygen flow only","Naloxone 0.4–2 mg IV/IM/intranasal — titrate to adequate breathing (avoid complete reversal in opioid-dependent patients)","Flumazenil","Caffeine"], answer:1, explanation:"Opioid overdose: respiratory depression + miosis + altered consciousness. Naloxone (Narcan): IV/IM/SC/intranasal. Start with 0.1 mg IV and titrate (avoid precipitating withdrawal). Repeat dosing may be needed (opioid outlasts naloxone). Monitor 4–6 hours." },
    { id:"p8q77", question:"The nurse suspects pulmonary embolism in a postoperative patient. Expected ABG finding:", options:["Respiratory acidosis with elevated CO2","Respiratory alkalosis (hyperventilation blows off CO2): low pH, low PaCO2, low PaO2","Metabolic acidosis with elevated lactate only","Normal ABG excludes PE"], answer:1, explanation:"Acute PE: tachypnea → respiratory alkalosis (low PaCO2), hypoxemia (low PaO2), increased A-a gradient. As patient tires: CO2 may normalize then rise (respiratory failure). Normal ABG does NOT exclude PE." },
    { id:"p8q78", question:"Suctioning a tracheostomy — the catheter should be inserted:", options:["To the carina and then pulled back","Just past the end of the tracheostomy tube (not beyond the carina)","Into the main bronchus","Only to the stoma level"], answer:1, explanation:"Tracheostomy suction: insert catheter just past the end of the trach tube (not to carina — causes mucosal trauma, coughing, bronchospasm). Pre-oxygenate, suction on withdrawal with rotating motion for ≤10–15 seconds." },
    { id:"p8q79", question:"Myocardial infarction (STEMI) — which leads show inferior MI?", options:["V1–V4","I, aVL","II, III, aVF (and right coronary artery territory)","V5, V6"], answer:2, explanation:"ECG territory: Inferior (II, III, aVF): RCA. Anterior (V1–V4): LAD. Lateral (I, aVL, V5–V6): LCx. Posterior MI: ST depression V1–V3 + tall R waves (mirror image). Recognizing territory helps anticipate complications." },
    { id:"p8q80", question:"A patient is receiving IV potassium. The maximum safe IV rate for peripheral administration is:", options:["40 mEq/hr","100 mEq/hr","10–20 mEq/hr peripherally (40 mEq/hr via central line for severe hypokalemia)","5 mEq/hr only"], answer:2, explanation:"IV potassium: peripheral max 10–20 mEq/hr (peripheral vein irritation). Central line: up to 40 mEq/hr for severe hypokalemia with cardiac monitoring. Never give undiluted IV K+ bolus — cardiac arrest risk. Concentration: max 40 mEq/L peripheral." },
    { id:"p8q81", question:"Hemorrhagic shock — which fluid is FIRST-LINE for initial resuscitation?", options:["5% dextrose","Normal saline (0.9% NaCl) or Lactated Ringer's (preferred)","Albumin 5%","Sterile water"], answer:1, explanation:"Hemorrhagic shock: IV crystalloid (NS or LR preferred for fluid expansion) while blood products are obtained. LR preferred over NS for large volumes (NS causes hyperchloremic metabolic acidosis). Balanced resuscitation targets 1:1:1 blood products." },
    { id:"p8q82", question:"A patient develops tracheal deviation to the right after central line insertion. The nurse suspects:", options:["Normal finding","Left tension pneumothorax (trachea deviates AWAY from affected side)","Right hemothorax","Air embolism"], answer:1, explanation:"Tracheal deviation after central line: immediate concern for tension pneumothorax (complication of subclavian/jugular line placement). Trachea deviates AWAY from the affected (tension) side. Immediate needle decompression of left side." },
    { id:"p8q83", question:"When is transcutaneous pacing indicated?", options:["Ventricular fibrillation","Asystole (as bridge) and symptomatic bradycardia unresponsive to atropine","Stable atrial fibrillation","Tachycardias"], answer:1, explanation:"Transcutaneous (external) pacing: symptomatic bradycardia not responding to atropine, complete heart block, second-degree Mobitz II, and asystole (bridge). Apply pads (anterior-posterior position preferred), set rate (~70 bpm), increase mA until capture." },
    { id:"p8q84", question:"The nurse manages a patient with severe TBI (GCS 8). Which intervention INCREASES ICP?", options:["Head elevated 30°","Hyperventilation (PCO2 35–40 mmHg)","Cluster nursing care activities (multiple stimulations together)","Osmotic therapy with mannitol"], answer:2, explanation:"Clustered nursing care activities (suctioning, repositioning, bathing in rapid succession) cause cumulative ICP spikes. Space activities ≥15 minutes apart. Also avoid: hyperthermia, hypoxia, hypotension, hyponatremia — all raise ICP." },
    { id:"p8q85", question:"A patient in status epilepticus — after failed benzodiazepines, which drug is next?", options:["Oral carbamazepine","IV levetiracetam, IV valproate, or IV fosphenytoin (second-line antiseizure medications)","IV glucose only","Surgical intervention"], answer:1, explanation:"Status epilepticus treatment ladder: 1st line benzodiazepines (lorazepam IV, midazolam IM) → 2nd line: levetiracetam IV, valproate IV, or fosphenytoin/phenytoin IV → 3rd line (refractory): general anesthesia (propofol, midazolam infusion, phenobarbital)." },
    { id:"p8q86", question:"Prone positioning in ARDS is indicated for:", options:["All ventilated patients","Moderate-severe ARDS (PaO2/FiO2 <150) for ≥16 hours/day to improve oxygenation and mortality","Mild ARDS only","Cardiac patients only"], answer:1, explanation:"Prone positioning in ARDS (PaO2/FiO2 <150): ≥16 continuous hours/day. Redistributes perfusion to better-ventilated dorsal lung regions, improves V/Q matching, reduces VALI. PROSEVA trial: reduced 28-day mortality by ~50%." },
    { id:"p8q87", question:"Cricothyrotomy is performed when:", options:["RSI is preferred","Cannot intubate, cannot oxygenate (CICO) situation — surgical airway as last resort","Routine tracheostomy","Patient refuses intubation"], answer:1, explanation:"Cricothyrotomy (surgical airway): CICO scenario — failed intubation attempts AND oxygenation impossible. Needle cricothyrotomy (temporizing, jet ventilation) or surgical cricothyrotomy (scalpel-finger-tube technique). Converts to formal tracheostomy later." },
    { id:"p8q88", question:"A patient with myasthenic crisis has increasing respiratory failure. The BEST intervention:", options:["Increase neostigmine dose","IV immunoglobulin (IVIG) or plasma exchange (PLEX) + respiratory support (intubation if needed)","Corticosteroids alone","Anticholinesterase drugs only"], answer:1, explanation:"Myasthenic crisis: acetylcholine receptor antibodies worsen, causing respiratory failure. Treatment: ICU admission, respiratory support (intubation if FVC <15 mL/kg or NIF <−25 cmH2O), IVIG or PLEX (rapid immunomodulation), avoid triggering drugs." },
    { id:"p8q89", question:"Which ECG change is characteristic of hyperkalemia?", options:["ST elevation","Shortened QT interval and peaked T waves (early), wide QRS, sine wave pattern, VF (late)","Prolonged PR and ST depression","Delta waves and short PR"], answer:1, explanation:"Hyperkalemia ECG progression: peaked (tall, narrow, symmetric) T waves (earliest) → widened PR → wide QRS → loss of P waves → sine wave (QRS-T merge) → VF/asystole. Treat at peaked T wave stage." },
    { id:"p8q90", question:"Therapeutic hypothermia (TTM) after cardiac arrest is targeted at:", options:["32–36°C for 24–48 hours","28–30°C for 12 hours","38–39°C","Normal temperature (37°C) only"], answer:0, explanation:"TTM: maintain temperature at 32–36°C for ≥24 hours after cardiac arrest (VF/pVT and non-shockable rhythms) in comatose survivors. Reduces neurological injury. Avoid fever (≥37.7°C) for 72 hours post-arrest." },
    { id:"p8q91", question:"A patient receiving blood transfusion develops fever (temp rise >1°C) and chills during the transfusion. The nurse suspects:", options:["Anaphylaxis","Febrile non-hemolytic transfusion reaction (FNHTR) — most common transfusion reaction","Hemolytic reaction","Septic reaction from contaminated blood"], answer:1, explanation:"FNHTR (most common): WBC cytokines in donor blood cause fever/chills 1–6 hours after start. Stop transfusion, notify blood bank, give antipyretics, restart (if no hemolysis confirmed) with leukoreduced blood in future." },
    { id:"p8q92", question:"Respiratory rate goal during mechanical ventilation for ARDS:", options:["8–10 breaths/min","12–16 breaths/min","Low tidal volume ventilation (6 mL/kg IBW), PEEP titration — not specifically RR but RR adjusted to achieve target pH","30 breaths/min"], answer:2, explanation:"ARDSNet lung protective ventilation: TV 6 mL/kg ideal body weight (IBW), plateau pressure ≤30 cmH2O, PEEP ≥5 cmH2O, FiO2 titrated, RR up to 35/min to maintain pH ≥7.30, permissive hypercapnia acceptable." },
    { id:"p8q93", question:"A patient in the ED has swallowed a button battery. Priority management:", options:["Wait and observe","Activated charcoal","Urgent endoscopic removal — button batteries cause liquefactive necrosis in the esophagus within 2 hours","Induced vomiting"], answer:2, explanation:"Button battery ingestion: EMERGENCY if in esophagus. Generates hydroxide ions (electrolysis) → rapid liquefactive necrosis of esophagus within 2 hours → perforation, fistula, death. Urgent endoscopic removal. Honey may delay injury temporarily in children." },
    { id:"p8q94", question:"The best indicator of effective CPR during cardiac arrest is:", options:["Visible chest compressions","Pupil dilation","EtCO2 (end-tidal CO2) ≥10–20 mmHg (reflects cardiac output)","Skin color change"], answer:2, explanation:"EtCO2 during CPR: reflects pulmonary blood flow (cardiac output during CPR). EtCO2 ≥10 mmHg = adequate CPR. EtCO2 ≥20 mmHg = good perfusion. Sudden rise in EtCO2 (to ≥40) = ROSC (return of spontaneous circulation)." },
    { id:"p8q95", question:"A patient is admitted with suspected meningococcal meningitis. FIRST priority after airway/breathing:", options:["Lumbar puncture","CT scan brain","Immediate IV ceftriaxone (antibiotics) — do NOT delay for CT or LP if patient is deteriorating","Blood cultures only then wait"], answer:2, explanation:"Bacterial meningitis (suspected): antibiotics within 30 minutes of ED arrival. Blood cultures × 2 (take < 5 min), then antibiotics. LP can be done after antibiotics if indicated — delay in antibiotics is the main cause of death. Dexamethasone IV before/with first antibiotic dose." },
    { id:"p8q96", question:"A patient with suspected spinal cord injury has priapism (involuntary erection) and hypotension with bradycardia. This indicates:", options:["Septic shock","Neurogenic shock from complete spinal cord injury — loss of sympathetic outflow","Cardiogenic shock","Anaphylaxis"], answer:1, explanation:"Neurogenic shock signs: warm skin, bradycardia (paradoxical), hypotension, priapism (in males), loss of reflexes below injury, bladder/bowel dysfunction. Priapism + bradycardia + hypotension = neurogenic shock until proven otherwise." },
    { id:"p8q97", question:"The treatment for acute severe hyponatremia (Na+ <120 mEq/L with symptoms):", options:["Normal saline only","Restrict free water only","Hypertonic saline (3% NaCl) — increase Na+ by 1–2 mEq/L/hr initially, max 8–10 mEq/L per 24 hours (avoid central pontine myelinolysis)","No treatment needed"], answer:2, explanation:"Symptomatic severe hyponatremia: hypertonic saline (3% NaCl). Correct at 1–2 mEq/L/hr initially (rapid for severe symptoms), then slow correction. Max 8–10 mEq/L per 24 hours. Too rapid correction → central pontine myelinolysis (locked-in syndrome)." },
    { id:"p8q98", question:"The term 'dead space' ventilation means:", options:["Alveolar ventilation without perfusion (high V/Q ratio)","Ventilation of airways but not alveoli","Perfusion without ventilation (shunt — low V/Q)","The volume of the trachea and bronchi"], answer:0, explanation:"Dead space: ventilation without perfusion (V/Q = ∞). Alveolar dead space: alveoli ventilated but not perfused (PE is classic cause). Anatomical dead space: conducting airways (~150 mL in adults). Increased dead space: raised PaCO2." },
    { id:"p8q99", question:"A critically ill patient in the ICU suddenly becomes hypotensive with warm skin, fever 39.8°C, and WBC 24,000. The nurse suspects:", options:["Hypovolemic shock","Cardiogenic shock","Septic shock (distributive) — vasodilation, fever, high WBC","Obstructive shock"], answer:2, explanation:"Septic shock: infection → systemic vasodilation → warm skin, fever, tachycardia, hypotension (refractory to fluids), high or low WBC, elevated lactate. Treatment: Hour-1 bundle (cultures, antibiotics, fluids, vasopressors)." },
    { id:"p8q100", question:"Which condition requires immediate pericardiocentesis?", options:["Chronic stable pericarditis","Cardiac tamponade with hemodynamic compromise (Beck's triad + pulsus paradoxus >10 mmHg)","Pericardial effusion found incidentally on echo","Viral pericarditis"], answer:1, explanation:"Cardiac tamponade with hemodynamic compromise: immediate pericardiocentesis (needle aspiration under echo/fluoroscopy guidance). Removal of even 50–100 mL dramatically improves cardiac output. Surgical window for recurrent effusions." }
  ]
};
export default phase8;
